#include <stdio.h>
void sortZeroOneTwo(int* nums, int numsSize) {
    int count0 = 0, count1 = 0, count2 = 0;
    for (int i = 0; i < numsSize; i++) {
        if (nums[i] == 0) count0++;
        else if (nums[i] == 1) count1++;
        else count2++;
    }
    int index = 0;
    while (count0--) {
        nums[index++] = 0;
    }
    while (count1--) {
        nums[index++] = 1;
    }
    while (count2--) {
        nums[index++] = 2;
    }
}
int main() {
    int nums[] = {1, 0, 2, 1, 0};
    int numsSize = sizeof(nums) / sizeof(nums[0]);
    sortZeroOneTwo(nums, numsSize);
    for (int i = 0; i < numsSize; i++) {
        printf("%d ", nums[i]);
    }
    return 0;
}

